+  release(buffer: Float32Array): void {
+    const size = buffer.length;
+    if (!this.pools.has(size)) {
+      this.pools.set(size, []);
+    }
+    const pool = this.pools.get(size)!;
+    if (pool.length < this.maxPoolSize) {
+      // Clear buffer before returning to pool
+      buffer.fill(0);
+      pool.push(buffer);
+    }
+  }
+
+  /**
