+    throw new Error(`${name} must be a non-negative finite number`);
+  }
+  if (dimension > MAX_VECTOR_DIMENSION) {
+    throw new Error(`${name} exceeds maximum allowed size of ${MAX_VECTOR_DIMENSION}`);
+  }
+}
