+function safeJSONParse<T>(json: string, validator: (obj: unknown) => obj is T): T {
+  let parsed: unknown;
+  try {
+    parsed = JSON.parse(json);
+  } catch (e) {
+    throw new Error('Invalid JSON format');
+  }
+  if (!validator(parsed)) {
