+    this.map.set(key, newNode);
+
+    // Evict if over capacity
+    if (this.map.size > this.capacity) {
+      this.evictLRU();
+    }
+  }
+
+  /**
+   * Check if key exists - O(1)
+   */
+  has(key: string): boolean {
+    return this.map.has(key);
+  }
+
+  /**
+   * Delete key from cache - O(1)
+   */
+  delete(key: string): boolean {
+    const node = this.map.get(key);
+    if (!node) return false;
+
+    this.removeNode(node);
+    this.map.delete(key);
+    return true;
+  }
+
+  /**
+   * Clear all entries
+   */
+  clear(): void {
+    this.map.clear();
+    this.head = null;
+    this.tail = null;
+    this._hits = 0;
+    this._misses = 0;
+  }
+
+  /**
+   * Get current size
+   */
+  get size(): number {
+    return this.map.size;
+  }
+
+  /**
+   * Get cache statistics
+   */
+  get stats(): { hits: number; misses: number; hitRate: number; size: number; maxSize: number } {
+    const total = this._hits + this._misses;
+    return {
+      hits: this._hits,
+      misses: this._misses,
+      hitRate: total > 0 ? this._hits / total : 0,
+      size: this.map.size,
+      maxSize: this.capacity,
+    };
+  }
+
+  /**
+   * Move node to front of list (most recently used)
+   */
+  private moveToFront(node: CacheNode): void {
+    if (node === this.head) return;
+
+    // Remove from current position
+    this.removeNode(node);
+
+    // Add to front
+    node.prev = null;
+    node.next = this.head;
+    if (this.head) {
+      this.head.prev = node;
+    }
+    this.head = node;
+
+    if (!this.tail) {
+      this.tail = node;
+    }
+  }
+
+  /**
+   * Remove node from list
+   */
+  private removeNode(node: CacheNode): void {
+    if (node.prev) {
+      node.prev.next = node.next;
+    } else {
+      this.head = node.next;
+    }
+
+    if (node.next) {
+      node.next.prev = node.prev;
+    } else {
+      this.tail = node.prev;
+    }
+  }
+
+  /**
+   * Evict least recently used entry
+   */
+  private evictLRU(): void {
+    if (!this.tail) return;
+
+    const lruKey = this.tail.key;
+    this.removeNode(this.tail);
+    this.map.delete(lruKey);
+  }
+}
+
+// ============================================================================
+// Semaphore for Concurrency Control
+// ============================================================================
+
+/**
+ * Simple semaphore for controlling concurrent operations
+ */
+class Semaphore {
+  private permits: number;
+  private waiting: Array<() => void> = [];
+  private maxWaiting: number;
+
+  constructor(permits: number, maxWaiting: number = 1000) {
+    // Enforce maximum concurrent requests for security
+    this.permits = Math.min(Math.max(1, permits), MAX_CONCURRENT_REQUESTS);
+    this.maxWaiting = maxWaiting;
+  }
+
+  async acquire(): Promise<void> {
+    if (this.permits > 0) {
+      this.permits--;
+      return;
+    }
+
+    // Prevent unbounded queue growth (deadlock protection)
+    if (this.waiting.length >= this.maxWaiting) {
+      throw new Error('Too many pending requests - semaphore queue full');
+    }
+
+    return new Promise<void>((resolve) => {
+      this.waiting.push(resolve);
+    });
+  }
+
+  release(): void {
+    const next = this.waiting.shift();
+    if (next) {
+      next();
+    } else {
+      this.permits++;
+    }
+  }
+
+  async withLock<T>(fn: () => Promise<T>): Promise<T> {
+    await this.acquire();
+    try {
+      return await fn();
+    } finally {
+      this.release();
+    }
+  }
+}
