+/**
+ * Buffer pool for reusing Float32Arrays to avoid GC pressure
+ */
+class BufferPool {
+  private pools: Map<number, Float32Array[]> = new Map();
+  private maxPoolSize = MAX_BUFFER_POOL_SIZE;
+  private totalMemory = 0;
