+  private computeBlockScores(
+    query: Float32Array,
+    key: Float32Array,
+    qStart: number,
+    qEnd: number,
+    kStart: number,
+    kEnd: number,
+    dim: number,
+    scale: number
+  ): void {
+    const qBlockSize = qEnd - qStart;
+    const kBlockSize = kEnd - kStart;
+    const unrolledDim = dim - (dim % 8);
+
+    for (let qi = 0; qi < qBlockSize; qi++) {
+      const qOffset = (qStart + qi) * dim;
+
+      for (let ki = 0; ki < kBlockSize; ki++) {
